#include "sda_config.h"
#include <string.h>
#include <stdio.h>
#include <stdlib.h>
void sda_config_defaults(sda_config*c){ memset(c,0,sizeof*c); strcpy(c->solver,"target-q"); c->support_min=0; c->mpfr_precision=SDA_MPFR_DEFAULT_PRECISION; c->renyi_order=513; }
int sda_config_builtin(const char*n,sda_config*c){ sda_config_defaults(c); strcpy(c->scheme,(!strncmp(n,"falcon",6))?"Falcon":"Frodo"); strcpy(c->parameter_set,n); if(!strcmp(n,"frodo640")){c->sigma=2.8;c->support_max=12;c->precision_k=15; sda_parse_u128("14534",&c->manuscript_q);} else if(!strcmp(n,"frodo976")){c->sigma=2.3;c->support_max=10;c->precision_k=15; sda_parse_u128("7442",&c->manuscript_q);} else if(!strcmp(n,"frodo1344")){c->sigma=1.4;c->support_max=6;c->precision_k=15; sda_parse_u128("102",&c->manuscript_q);} else if(!strcmp(n,"falcon")){c->sigma=1.8205;c->support_max=18;c->precision_k=72; sda_parse_u128("4696835740265763827900",&c->manuscript_q);} else return -1; c->target_q=c->manuscript_q; sda_print_u128(c->target_q,c->target_q_text,sizeof c->target_q_text); return 0; }
int sda_config_load(const char*path,sda_config*c){ FILE*f=fopen(path,"r"); if(!f)return-1; sda_config_defaults(c); char k[64],v[128]; while(fscanf(f," %63[^=]=%127s",k,v)==2){ if(!strcmp(k,"name"))strncpy(c->parameter_set,v,31); else if(!strcmp(k,"scheme"))strncpy(c->scheme,v,31); else if(!strcmp(k,"sigma"))c->sigma=strtod(v,0); else if(!strcmp(k,"support_min"))c->support_min=atoi(v); else if(!strcmp(k,"support_max"))c->support_max=atoi(v); else if(!strcmp(k,"precision_k"))c->precision_k=atoi(v); else if(!strcmp(k,"renyi_order"))c->renyi_order=atol(v); else if(!strcmp(k,"target_q")){strncpy(c->target_q_text,v,79);sda_parse_u128(v,&c->target_q);c->manuscript_q=c->target_q;} int ch; while((ch=fgetc(f))!='\n'&&ch!=EOF){} } fclose(f); return 0; }
